#include <Wire.h>
#include <LiquidCrystal_I2C.h>

extern bool electroplating_quality_check(float ph,float current_mA,float temp_C);

LiquidCrystal_I2C lcd(0x27,16,2);
const int CURRENT_PWM=9,PH_PIN=A0,CURR_PIN=A1,NTC_PIN=A2;
const float I_SP=300.0f;
const float R_NTC=10000.0f,B_NTC=3950.0f;
float err_i=0;

// === pH Sensor ===
void ph_init(){pinMode(PH_PIN,INPUT);}
float ph_read(){return analogRead(PH_PIN)*14.0f/1023.0f;}

// === Current Source ===
void current_init(){pinMode(CURRENT_PWM,OUTPUT);analogWrite(CURRENT_PWM,0);}
void current_set(float mA){int p=(int)(mA/500.0f*255);analogWrite(CURRENT_PWM,constrain(p,0,255));}
float current_read(){return analogRead(CURR_PIN)*500.0f/1023.0f;}

// === NTC Bath Temp ===
void temp_init(){pinMode(NTC_PIN,INPUT);}
float temp_read(){float v=analogRead(NTC_PIN)*3.3f/1023.0f;float r=R_NTC*v/(3.3f-v);return 1.0f/(1.0f/298.15f+(1.0f/B_NTC)*log(r/R_NTC))-273.15f;}

// === LCD Status ===
void lcd_update(float ph,float curr,float temp,bool fault){
  lcd.setCursor(0,0);lcd.print("pH:");lcd.print(ph,1);lcd.print(" I:");lcd.print(curr,0);lcd.print("mA");
  lcd.setCursor(0,1);if(fault){lcd.print("!! FAULT STOP  ");}else{lcd.print("T:");lcd.print(temp,0);lcd.print("C OK       ");}}

// === Fault Handler ===
bool fault_check(float ph,float curr,float temp){
  if(!electroplating_quality_check(ph,curr,temp)){current_set(0);Serial.println("FAULT:WINDOW");return true;}return false;}

// === Current PI Controller ===
void current_control(float sp,float pv,float dt){
  float e=sp-pv;err_i+=e*dt;
  float out=sp+2.0f*e+0.5f*err_i;
  current_set(constrain(out,0,500));}

void setup(){
  Serial.begin(115200);
  Wire.begin();
  ph_init();current_init();temp_init();
  lcd.init();lcd.backlight();
  Serial.println("t_s,ph,curr_mA,temp_C,fault");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<5.0f)return;
  lastMs=now;
  float ph=ph_read(),curr=current_read(),temp=temp_read();
  bool fault=fault_check(ph,curr,temp);
  if(!fault)current_control(I_SP,curr,dt);
  lcd_update(ph,curr,temp,fault);
  Serial.print(now/1000);Serial.print(',');Serial.print(ph,2);Serial.print(',');Serial.print(curr,1);Serial.print(',');Serial.print(temp,1);Serial.print(',');Serial.println(fault?1:0);
}
